import { Component, DestroyRef, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXDownloadStatus, AXNetworkService, AXUploadStatus } from '@acorex/core/network';

@Component({
  selector: 'app-network-basic',
  template: `
    @if (network.status()) {
      <span>Online</span>
    } @else {
      <span>Offline - transfers are unavailable</span>
    }

    <input type="file" (change)="upload($event)" />
    <button type="button" (click)="download()">Download report</button>

    <progress [value]="progress()" max="100"></progress>
    <p>{{ statusText() }}</p>
  `,
})
export class NetworkBasicComponent {
  private readonly destroyRef = inject(DestroyRef);
  protected readonly network = inject(AXNetworkService);

  protected readonly progress = signal(0);
  protected readonly statusText = signal('');

  upload(event: Event) {
    const file = (event.target as HTMLInputElement).files?.[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('file', file);

    const task = this.network.upload<{ id: string }>('/api/files', formData);
    task.events.pipe(takeUntilDestroyed(this.destroyRef)).subscribe((event) => {
      this.progress.set(event.progress);
      this.statusText.set(event.status);

      if (event.status === AXUploadStatus.UploadComplete) {
        console.log('Uploaded file id:', event.result?.id);
      }
    });

    task.start();
  }

  download() {
    const task = this.network.download('/api/files/report.pdf');
    task.events.pipe(takeUntilDestroyed(this.destroyRef)).subscribe((event) => {
      this.progress.set(event.progress);
      this.statusText.set(event.status);

      if (event.status === AXDownloadStatus.DownloadComplete && event.data) {
        console.log('Downloaded bytes:', event.data.size);
      }
    });
  }
}

import { Component, DestroyRef, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXNetworkService, AXUploadStatus } from '@acorex/core/network';

@Component({
  selector: 'app-upload',
  template: `
    <input type="file" (change)="onFile($event)" />
    <progress [value]="progress()" max="100"></progress>
    <p>{{ statusText() }}</p>
  `,
})
export class UploadComponent {
  private readonly destroyRef = inject(DestroyRef);
  private network = inject(AXNetworkService);

  progress = signal(0);
  statusText = signal('');

  onFile(event: Event) {
    const file = (event.target as HTMLInputElement).files?.[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('file', file);

    const task = this.network.upload<{ id: string }>('/api/files', formData);

    task.events.pipe(takeUntilDestroyed(this.destroyRef)).subscribe((event) => {
      this.progress.set(event.progress);
      this.statusText.set(event.status);

      if (event.status === AXUploadStatus.UploadComplete) {
        console.log('Server response:', event.result);
      }
      if (event.status === AXUploadStatus.UploadFailed) {
        console.error(event.message);
      }
    });

    task.start(); // Required — upload does not auto-start
  }
}

import { HttpRequest } from '@angular/common/http';
import { inject } from '@angular/core';
import { AXNetworkService } from '@acorex/core/network';

async function uploadWithAuth(file: File, token: string) {
  const network = inject(AXNetworkService);

  const formData = new FormData();
  formData.append('files', file);

  const request = new HttpRequest('POST', '/api/v1/files', formData, {
    reportProgress: true,
    responseType: 'json',
    headers: { Authorization: `Bearer ${token}` },
  });

  const task = network.upload<{ url: string }>(request);
  task.events.subscribe(console.log);
  task.start();
}

import { inject } from '@angular/core';
import { AXNetworkService, AXUploadTask } from '@acorex/core/network';

let activeTask: AXUploadTask<unknown> | null = null;

function startUpload(formData: FormData) {
  const network = inject(AXNetworkService);
  activeTask = network.upload('/api/upload', formData);
  activeTask.events.subscribe((e) => console.log(e.progress));
  activeTask.start();
}

function cancelUpload() {
  activeTask?.cancel();
  activeTask = null;
}

import { Component, DestroyRef, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXDownloadStatus, AXNetworkService } from '@acorex/core/network';

@Component({
  selector: 'app-download',
  template: `
    <button type="button" (click)="download()">Download</button>
    <p>{{ progress() }}% — {{ label() }}</p>
  `,
})
export class DownloadComponent {
  private readonly destroyRef = inject(DestroyRef);
  private network = inject(AXNetworkService);
  private task: ReturnType<AXNetworkService['download']> | null = null;

  progress = signal(0);
  label = signal('');

  download() {
    this.task = this.network.download('https://example.com/files/report.pdf');

    this.task.events.pipe(takeUntilDestroyed(this.destroyRef)).subscribe((event) => {
      this.progress.set(event.progress);
      this.label.set(event.status);

      if (event.status === AXDownloadStatus.DownloadComplete && event.data) {
        this.saveBlob(event.data, 'report.pdf');
      }
    });
    // No start() — subscribing to events triggers the request
  }

  cancel() {
    this.task?.cancel();
  }

  private saveBlob(blob: Blob, filename: string) {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }
}

import { inject } from '@angular/core';
import { AXLoadingDialogService } from '@acorex/components/loading-dialog';
import { AXDownloadTask, AXNetworkService } from '@acorex/core/network';

function downloadLargeFile(url: string) {
  const loadingDialog = inject(AXLoadingDialogService);
  const network = inject(AXNetworkService);

  let downloadTask: AXDownloadTask | null = null;

  const dialog = loadingDialog.show({
    title: 'Download file...',
    mode: 'determinate',
    progressValue: 0,
    text: 'Waiting...',
    buttons: [
      {
        text: 'Cancel',
        color: 'danger',
        onClick: () => {
          downloadTask?.cancel();
          dialog.close();
        },
      },
    ],
  });

  downloadTask = network.download(url);
  downloadTask.events.subscribe((event) => {
    dialog.setProgressText(event.status);
    dialog.setProgressStatus(`${event.progress}%`);
    dialog.setProgressValue(event.progress);
  });
}

import { AXUploaderChangedEvent } from '@acorex/cdk/uploader';
import { inject } from '@angular/core';
import { AXNetworkService, AXUploadStatus } from '@acorex/core/network';

function handleUploaderChanged(e: AXUploaderChangedEvent) {
  const network = inject(AXNetworkService);
  const apiUrl = 'https://api.example.com/files';

  e.requests.forEach((request) => {
    const formData = new FormData();
    formData.append('files', request.file);

    const task = network.upload(apiUrl, formData);

    task.events.subscribe((event) => {
      if (event.status === AXUploadStatus.UploadFailed) {
        request.error(event.message);
      } else if (event.status === AXUploadStatus.UploadComplete) {
        request.finish(event.result);
      } else {
        request.setTransferredBytes(event.bytesTransferred);
      }
    });

    request.onStart.subscribe(() => task.start());
    request.onCancel.subscribe(() => task.cancel());
    request.upload();
  });
}
